import{_ as l,o as n,c as s,a2 as i}from"./chunks/framework.BnBoz4Zl.js";const u=JSON.parse('{"title":"第 17 章 结构化数据分析与可视化表达","description":"数据分析的目标不是生成更多图，而是让问题、口径、证据和限制更清楚。本章使用合成数据介绍通用方法，不展示真实部门、人员、样本和内部结论。 做到数据来源清楚、口径一致、处理可复现、图表回答问题、结论带证据、限制不隐藏。","frontmatter":{},"headers":[],"relativePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 17 章 会议结束不是终点，工作才刚刚开始/index.md","filePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 17 章 会议结束不是终点，工作才刚刚开始/index.md","lastUpdated":1784100816000}'),e={name:"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 17 章 会议结束不是终点，工作才刚刚开始/index.md"};function t(o,a,r,p,h,d){return n(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="第-17-章-结构化数据分析与可视化表达" tabindex="-1">第 17 章 结构化数据分析与可视化表达 <a class="header-anchor" href="#第-17-章-结构化数据分析与可视化表达" aria-label="Permalink to &quot;第 17 章 结构化数据分析与可视化表达&quot;">​</a></h1><p>数据分析的目标不是生成更多图，而是让问题、口径、证据和限制更清楚。本章使用合成数据介绍通用方法，不展示真实部门、人员、样本和内部结论。</p><h2 id="可应用到哪些任务" tabindex="-1">可应用到哪些任务 <a class="header-anchor" href="#可应用到哪些任务" aria-label="Permalink to &quot;可应用到哪些任务&quot;">​</a></h2><ul><li>问卷、意见反馈和满意度分析。</li><li>业务统计、任务进度和质量数据汇总。</li><li>分类比较、趋势观察和异常检查。</li><li>制作管理看板或专题汇报图表。</li></ul><h2 id="任务目标" tabindex="-1">任务目标 <a class="header-anchor" href="#任务目标" aria-label="Permalink to &quot;任务目标&quot;">​</a></h2><p>做到数据来源清楚、口径一致、处理可复现、图表回答问题、结论带证据、限制不隐藏。</p><h2 id="输入材料" tabindex="-1">输入材料 <a class="header-anchor" href="#输入材料" aria-label="Permalink to &quot;输入材料&quot;">​</a></h2><ul><li>原始数据副本和字段说明。</li><li>分析问题、目标读者和时间范围。</li><li>指标定义、分组规则和缺失值处理要求。</li><li>输出格式、隐私限制和最小展示粒度。</li></ul><h2 id="执行步骤" tabindex="-1">执行步骤 <a class="header-anchor" href="#执行步骤" aria-label="Permalink to &quot;执行步骤&quot;">​</a></h2><ol><li><strong>读取结构</strong>：先报告表名、字段、行数、数据类型、空值和异常，不修改原表。</li><li><strong>确认口径</strong>：把指标公式、时间范围、分组规则和排除条件写成分析说明。</li><li><strong>生成处理表</strong>：保留原始列，新增清洗列和计算列，记录每一步。</li><li><strong>先表后图</strong>：用汇总表核对数字，再选择比较、趋势、构成或分布图。</li><li><strong>结论绑定证据</strong>：每条结论引用具体指标和图表，同时说明样本、缺失和不确定性。</li><li><strong>隐私检查</strong>：小样本和自由文本可能识别个人，应合并、隐藏或只在受控环境查看。</li></ol><h2 id="合成示例" tabindex="-1">合成示例 <a class="header-anchor" href="#合成示例" aria-label="Permalink to &quot;合成示例&quot;">​</a></h2><p>使用 60 条虚构的“办公工具体验反馈”数据，分析使用频率、主要问题和改进建议。图表可以显示总体分布和匿名分组，但不展示个人回答或真实部门。</p><h3 id="可复制任务模板" tabindex="-1">可复制任务模板 <a class="header-anchor" href="#可复制任务模板" aria-label="Permalink to &quot;可复制任务模板&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请分析当前目录中的表格，先不要修改原文件。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>分析问题：{问题}</span></span>
<span class="line"><span>数据文件：{文件名}</span></span>
<span class="line"><span>时间范围：{范围}</span></span>
<span class="line"><span>指标口径：{定义或“待确认”}</span></span>
<span class="line"><span>分组规则：{规则}</span></span>
<span class="line"><span>隐私要求：不展示个人信息，不展示可识别的小样本</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请先输出字段、数据量、空值、异常和口径问题；</span></span>
<span class="line"><span>等我确认后再生成处理表、汇总表和图表；</span></span>
<span class="line"><span>每条结论必须引用证据，并说明样本量、缺失值和限制；</span></span>
<span class="line"><span>不得根据相关性推断因果，不得补造数据。</span></span></code></pre></div><h2 id="人工确认点" tabindex="-1">人工确认点 <a class="header-anchor" href="#人工确认点" aria-label="Permalink to &quot;人工确认点&quot;">​</a></h2><ul><li>数据是否完整、合法且允许用于本次分析。</li><li>指标、时间、分组和排除规则是否正确。</li><li>图表是否准确表达数据，没有隐藏低样本或负面结果。</li><li>结论是否超出证据，是否可能识别个人。</li></ul><h2 id="输出物与验收标准" tabindex="-1">输出物与验收标准 <a class="header-anchor" href="#输出物与验收标准" aria-label="Permalink to &quot;输出物与验收标准&quot;">​</a></h2><ul><li>数据质量报告：字段、空值、异常和处理建议清楚。</li><li>口径说明：每个指标可以复算。</li><li>汇总表与图表：数字一致，标题、单位、样本量完整。</li><li>结论证据表：结论、指标、图表和限制一一对应。</li></ul><h2 id="常见弯路与安全边界" tabindex="-1">常见弯路与安全边界 <a class="header-anchor" href="#常见弯路与安全边界" aria-label="Permalink to &quot;常见弯路与安全边界&quot;">​</a></h2><ul><li>为了图表整齐过滤小组，会造成覆盖不全。应保留全部分组并提示样本量。</li><li>只看平均值会掩盖分布差异。根据问题补充分布和异常值。</li><li>把开放文本全部公开会暴露个人，应先脱敏并控制访问。</li><li>不展示真实部门和个人数据，不把模型推断当管理结论。可复用数据质量表、口径表、图表清单和结论证据表。</li></ul>`,20)])])}const b=l(e,[["render",t]]);export{u as __pageData,b as default};
